package com.meession.etm.module.bpm.controller.admin.oa;
import com.meession.etm.framework.common.pojo.CommonResult; import com.meession.etm.module.bpm.controller.admin.oa.vo.BpmOADocumentSaveReqVO; import com.meession.etm.module.bpm.dal.dataobject.oa.*; import com.meession.etm.module.bpm.service.oa.BpmOADocumentService; import io.swagger.v3.oas.annotations.Operation; import io.swagger.v3.oas.annotations.tags.Tag; import jakarta.annotation.Resource; import jakarta.validation.Valid; import org.springframework.security.access.prepost.PreAuthorize; import org.springframework.validation.annotation.Validated; import org.springframework.web.bind.annotation.*; import java.util.*; import static com.meession.etm.framework.common.pojo.CommonResult.success; import static com.meession.etm.framework.security.core.util.SecurityFrameworkUtils.getLoginUserId;
@Tag(name="管理后台 - OA 文档") @RestController @RequestMapping("/bpm/oa/document") @Validated public class BpmOADocumentController { @Resource private BpmOADocumentService service; @PostMapping("/create") @Operation(summary="创建文档目录") @PreAuthorize("@ss.hasPermission('bpm:oa-document:create')") public CommonResult<Long> create(@Valid @RequestBody BpmOADocumentSaveReqVO r){return success(service.create(getLoginUserId(),r));} @PutMapping("/update") @PreAuthorize("@ss.hasPermission('bpm:oa-document:update')") public CommonResult<Boolean> update(@Valid @RequestBody BpmOADocumentSaveReqVO r){service.update(getLoginUserId(),r);return success(true);} @DeleteMapping("/archive") @PreAuthorize("@ss.hasPermission('bpm:oa-document:delete')") public CommonResult<Boolean> archive(@RequestParam Long id){service.archive(getLoginUserId(),id);return success(true);} @GetMapping("/list") @PreAuthorize("@ss.hasPermission('bpm:oa-document:query')") public CommonResult<List<BpmOADocumentDO>> list(@RequestParam(required=false) Long parentId){return success(service.list(getLoginUserId(),parentId));} @GetMapping("/versions") @PreAuthorize("@ss.hasPermission('bpm:oa-document:query')") public CommonResult<List<BpmOADocumentVersionDO>> versions(@RequestParam Long id){return success(service.versions(getLoginUserId(),id));} @PostMapping("/version") @PreAuthorize("@ss.hasPermission('bpm:oa-document:update')") public CommonResult<Long> version(@RequestParam Long id,@RequestParam Long fileId,@RequestParam(required=false) String summary){return success(service.addVersion(getLoginUserId(),id,fileId,summary));} @PostMapping("/member") @PreAuthorize("@ss.hasPermission('bpm:oa-document:update')") public CommonResult<Boolean> member(@RequestParam Long id,@RequestParam Long userId,@RequestParam Integer permission){service.addMember(getLoginUserId(),id,userId,permission);return success(true);} }
